    nyse_data = nyse_file
else:
    nyse_data = []

# Create mapping: symbol -> company name
company_names = {}
for stock in nyse_data:
    symbol = stock['Symbol']
    description = stock['Company Description']
    # Extract cleaner company name
    name = description.split('.')[0].strip()
    # Shorten long descriptions to just company name
    if 'specializes in' in name:
        name = name.split('specializes in')[0].strip()
    elif 'is a' in name:
        name = name.split('is a')[0].strip()
    elif 'is an' in name:
        name = name.split('is an')[0].strip()
    elif 'is part of' in name:
        name = name.split('is part of')[0].strip()
    elif ' is ' in name:
        name = name.split(' is ')[0].strip()

    company_names[symbol] = name

# We'll store up/down counts for each stock
stock_performance = {}

# Process in batches to be efficient - let's start with first 20 stocks to test
symbols_to_test = list(company_names.keys())[:20]

print('__RESULT__:')
print(json.dumps({
    'total_to_process': len(company_names),
    'test_batch_size': len(symbols_to_test),
    'sample_symbols': symbols_to_test[:5]
}))

